#include <bits/stdc++.h>
using namespace std;
int a[15],n,use[15],k;
void dfs(int pos) {
    if(pos==k+1) {
        for(int i=1;i<=k;i++)
            cout<<a[i]<<' ';
        cout<<endl;
        return;
    }
    for(int i=1;i<=n;i++)
        if(!use[i]){
            use[i]=1;
            a[pos]=i;
            dfs(pos+1);
            use[i]=0;
        }
}
int main(void){
    cin>>n>>k;
    dfs(1);
    return false;
}
